  known_issues = json('[{"ea839_cam_roller":"RESOLVED - roller rockers produced before 06/08/2018 had undersized needle bearings. 2020+ production has revised part 0P2109417"},{"ea839_pistons":"Ongoing concern - 034Motorsport investigation found piston rocking causes stress risers at oil drain holes leading to ringland fracture. 3 piston revisions exist. A8 340hp tune is milder than S4/SQ5 349-354hp, reducing stress"},{"recall_97EV_ecm":"NHTSA 21V111000 - Missing sealing pin on ECM connector, moisture ingress can cause stalling. Dealer fix available"},{"recall_42L1_rear_axle":"NHTSA 21V295000 - Rear axle trailing arm lock nut could break. Dealer fix + follow-up recall 42L5 for alignment"},{"tsb_suspension_creak":"TSB 4022442058489/6 - Front suspension creaking on 2019-2022 A8/S8, control arm bushings"},{"mib3_upgrade":"Facelift uses MIB3 (Qualcomm) replacing MIB2 (Nvidia) - faster, more stable, not backward-compatible"},{"digital_matrix_led":"New DMD headlights with 1.3M micromirrors - unproven long-term aging but no widespread failures reported"}]'),
  score_notes = json('[{"engine":"+3 vs 2018: cam roller failure fully resolved for post-06/2018 production. Piston ringland risk unchanged across all years but A8 tune is milder. Water pump and motor mount failures remain possible","transmission":"Same proven ZF 8HP AL552 - excellent across VAG lineup, electric oil pump for MHEV coasting","chassis":"-1 vs 2018: rear axle trailing arm recall (42L1) and front suspension creaking TSB for 2019-2022. Core ASF structure unchanged and excellent","electronics":"+1 vs 2018: MIB3 upgrade is meaningful improvement over MIB2. Offset by ECM seal recall (97EV) and instrument panel software recall. More digital systems (Digital Matrix LED, Digital OLED) add complexity","ease_of_repair":"-2 vs 2018: MIB3, Digital Matrix LED, Digital OLED, active suspension option all add repair complexity. ASF still requires certified shops for body work"}]')
